def install_rational_package():
    # ...

    def is_equal(x, y):
        return numer(x) * denom(y) == numer(y) * denom(x)

    put("is_equal", llist("rational", "rational"), is_equal)

    # ...

def install_complex_package():
    # ...

    def is_equal(z1, z2):
        return (imag_part(z1) == imag_part(z2)
                if real_part(z1) == real_part(z2)
                else False)

    put("is_equal", llist("complex", "complex"),
            is_equal)

